import { mkdir } from "node:fs/promises";
import path from "node:path";
import { expect, test } from "playwright/test";

// Generated by Intent POC. This tracked Playwright spec is regenerated in place when the same intent path is requested.
const baseUrl = process.env.INTENT_POC_BASE_URL ?? "http://127.0.0.1:6006";
const screenshotRoot = process.env.INTENT_POC_E2E_SCREENSHOT_ROOT ?? "/home/andre/Desktop/GeniusMonkey/Intent POC/artifacts/library";

test.describe("Intent-driven flow for intent-poc-app", () => {
  test("Verify Reactive Metadata Updates", async ({ page }) => {
    await test.step("Intent Studio Prompt Run", async () => {
      await page.goto(new URL("/", baseUrl).toString(), { waitUntil: "domcontentloaded" });
      await page.waitForSelector("#prompt-input");
      await expect(page.locator("body"), "The Intent Studio prompt input is visible and ready for interaction.").toBeVisible();
      const screenshotPath = path.join(screenshotRoot, "bdd/intent-poc-app-verify-reactive-metadata-updates-spec", "shot-1-verify-reactive-metadata-updates-intent-studio.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
    await test.step("Work Scope Section Visible", async () => {
      await page.waitForSelector("#work-scope-panel");
      const target = page.locator("#work-scope-panel");
      await expect(target, "The work scope section is visible before interaction.").toBeVisible();
      const screenshotPath = path.join(screenshotRoot, "bdd/intent-poc-app-verify-reactive-metadata-updates-spec", "shot-2-verify-reactive-metadata-updates-work-scope-visible.png");
      await mkdir(path.dirname(screenshotPath), { recursive: true });
      await page.screenshot({ path: screenshotPath, fullPage: true });
    });
  });
});
